+/// Full mission transaction contract.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct MissionTxContract {
+    pub tx_version: u32,
+    pub intent: TxIntent,
+    pub plan: TxPlan,
+    pub lifecycle_state: MissionTxState,
+    pub outcome: TxOutcome,
+    #[serde(default)]
+    pub receipts: Vec<serde_json::Value>,
