+impl MissionTxContract {
+    /// Validate contract consistency.
+    pub fn validate(&self) -> Result<(), String> {
+        if self.plan.steps.is_empty() {
+            return Err("Transaction plan has no steps".to_string());
+        }
+        Ok(())
+    }
